const authData = $input.item.json;
const body = authData.body || {};

return {
  json: {
    campaign_id: body.campaign_id || '',
    week_number: parseInt(body.week_number) || 1,
    user_id: authData.user_id || '',
    assigned_products: body.assigned_products || [],
    storytelling_framework: body.storytelling_framework || '',
    content_language: body.content_language || 'English',
    day_count: parseInt(body.day_count) || 7,
    start_date: body.start_date || '',
    end_date: body.end_date || '',
    brand_voice_traits: body.brand_voice_traits || [],
    brand_voice_notes: body.brand_voice_notes || '',
    campaign_theme: body.campaign_theme || ''
  }
};

const params = $('Extract Params').first().json;
const icpRaw = $('Read ICP').first().json;
const productsRaw = $('Read Products').first().json;

// Parse ICP
let icp = {};
try {
  icp = Array.isArray(icpRaw) ? icpRaw[0] || {} : icpRaw || {};
} catch(e) { icp = {}; }

// Use assigned_products from frontend (preserves user's order) or fall back to Supabase
let products = [];
if (params.assigned_products && params.assigned_products.length > 0) {
  products = params.assigned_products;
} else {
  try {
    products = Array.isArray(productsRaw) ? productsRaw : [];
  } catch(e) { products = []; }
}

const dayCount = params.day_count || 7;

// Build product list with explicit day assignment (only for available days)
const productsList = products.slice(0, dayCount).map((p, i) => 'Day ' + (i + 1) + ': ' + p.name + ' (' + (p.category || 'General') + ')' + (p.description ? ' \u2014 ' + p.description : '')).join('\n');

const weekNum = params.week_number;

// Full 7-day storytelling framework definitions
const allDayThemes = [
  'Day 1 (Monday): CURIOSITY HOOK \u2014 Stop the scroll with intrigue and visual mystery.',
  'Day 2 (Tuesday): CRAFTSMANSHIP \u2014 Establish luxury credibility and authority.',
  'Day 3 (Wednesday): MEANING & SYMBOLISM \u2014 Build emotional connection.',
  'Day 4 (Thursday): TRANSFORMATION MOMENT \u2014 Show the impact when the product is worn/used.',
  'Day 5 (Friday): HIDDEN DETAIL / SURPRISE \u2014 Encourage shares through discovery.',
  'Day 6 (Saturday): LIFESTYLE ASPIRATION \u2014 Inspire desire and aspiration.',
  'Day 7 (Sunday): LEGACY & TIMELESSNESS \u2014 Build brand prestige.'
];

// Only include days 1 through dayCount
const frameworkLines = allDayThemes.slice(0, dayCount).join('\n');
const frameworkLabel = dayCount < 7 ? dayCount + '-DAY STORYTELLING FRAMEWORK (truncated from 7-day arc)' : '7-DAY STORYTELLING FRAMEWORK';

// Fix target_audience: stringify if object
let targetAudience = icp.target_audience || icp.demographics || 'General audience';
if (typeof targetAudience === 'object') {
  targetAudience = JSON.stringify(targetAudience);
}

// Build brand voice section from campaign data
let brandVoiceSection = '';
const traits = params.brand_voice_traits || [];
const voiceNotes = params.brand_voice_notes || '';
const campaignTheme = params.campaign_theme || '';
if (campaignTheme) {
  brandVoiceSection += '\n\nCAMPAIGN THEME: ' + campaignTheme + '\nAll topics MUST align with this campaign theme.';
}
if (traits.length > 0) {
  brandVoiceSection += '\n\nBRAND VOICE TRAITS (from user): ' + traits.join(', ');
}
if (voiceNotes) {
  brandVoiceSection += '\nBRAND VOICE NOTES (from user): ' + voiceNotes;
}

// Add brand doc summaries
try {
  const brandDocsItems = $('Read Brand Docs').all();
  const docSummary = brandDocsItems
    .map(item => item.json.summary_text || '')
    .filter(Boolean)
    .join('\n---\n')
    .substring(0, 3000);
  if (docSummary) {
    brandVoiceSection += '\n\nBRAND DOCUMENT GUIDELINES:\n' + docSummary;
  }
} catch(e) { /* no brand docs available */ }

const body = JSON.stringify({
  model: 'claude-sonnet-4-20250514',
  max_tokens: 4096,
  system: 'You are a luxury brand social media content strategist specializing in the 7-Day Storytelling Framework. Generate daily topics that follow the weekly narrative arc.' + (dayCount < 7 ? ' This week only has ' + dayCount + ' days, so adapt the arc accordingly.' : ''),
  messages: [{
    role: 'user',
    content: 'Generate ' + dayCount + ' daily social media content topics for WEEK ' + weekNum + ' of a monthly campaign.\n\nBUSINESS CONTEXT:\n- Industry: ' + (icp.industry || 'General') + '\n- Target Audience: ' + targetAudience + '\n- Brand Voice: ' + (icp.brand_voice || icp.tone || 'Professional and engaging') + '\n- Content Pillars: ' + JSON.stringify(icp.content_pillars || []) + '\n- Pain Points: ' + JSON.stringify(icp.pain_points || []) + brandVoiceSection + '\n\nPRODUCT ASSIGNMENTS (MANDATORY - each day MUST use its assigned product):\n' + productsList + '\n\n' + frameworkLabel + ' (MANDATORY - each day MUST follow its assigned theme):\n' + frameworkLines + '\n\nIMPORTANT RULES:\n- Each day MUST use the EXACT product assigned above (Day 1 product for day 1, Day 2 product for day 2, etc.)\n- Do NOT reassign or swap products between days\n- The product_name in your response MUST exactly match the assigned product name\n- Generate EXACTLY ' + dayCount + ' topics (days 1 through ' + dayCount + ')\n\n' + (params.storytelling_framework ? 'ADDITIONAL CONTEXT FROM FRONTEND:\n' + params.storytelling_framework + '\n\n' : '') + 'For each of the ' + dayCount + ' days provide:\n1. topic: A compelling topic title that reflects the day\'s storytelling theme (max 60 chars)\n2. description: Brief description of the post angle tied to the theme (max 150 chars)\n3. content_angle: Specific approach for this theme\n4. product_name: The EXACT product name assigned to this day (from the list above)\n5. storytelling_theme: The theme name\n\nReturn ONLY a valid JSON array of ' + dayCount + ' objects with keys: day_number (1-' + dayCount + '), topic, description, content_angle, product_name, storytelling_theme. No markdown.'
  }]
});

return {
  json: {
    apiBody: body,
    user_id: params.user_id,
    campaign_id: params.campaign_id,
    week_number: weekNum,
    products: products,
    day_count: dayCount
  }
};

const input = $input.item.json;
const prepData = $('Prepare Claude Prompt').first().json;

const dayCount = prepData.day_count || 7;

let raw = '';
try {
  raw = input.content[0].text;
} catch(e) { raw = '[]'; }

let topics = [];
try {
  topics = JSON.parse(raw);
} catch(e) {
  const stripped = raw.replace(/```(?:json)?\s*/g, '').replace(/```\s*$/g, '').trim();
  try { topics = JSON.parse(stripped); } catch(e2) {
    const match = stripped.match(/\[[\s\S]*\]/);
    if (match) { try { topics = JSON.parse(match[0]); } catch(e3) { topics = []; } }
  }
}

if (!Array.isArray(topics)) topics = [];

const products = prepData.products || [];

const validThemes = ['curiosity_hook','craftsmanship','meaning_symbolism','transformation','hidden_detail','lifestyle_aspiration','legacy_timelessness'];

const allThemes = ['curiosity_hook','craftsmanship','meaning_symbolism','transformation','hidden_detail','lifestyle_aspiration','legacy_timelessness'];
const dayThemeMap = {};
for (let d = 1; d <= dayCount; d++) {
  dayThemeMap[d] = allThemes[d - 1] || null;
}

const mapped = topics.slice(0, dayCount).map((t, i) => {
  const dayNum = t.day_number || (i + 1);
  const dayIndex = dayNum - 1;

  // PRIMARY: Positional match - day 1 = products[0], day 2 = products[1], etc.
  // The prompt explicitly assigns products by day position, so this is the most reliable.
  let productId = null;
  let productName = t.product_name || null;

  if (dayIndex >= 0 && dayIndex < products.length && products[dayIndex] && products[dayIndex].id) {
    productId = products[dayIndex].id;
    // Use the real product name from our data, not Claude's version
    if (products[dayIndex].name) productName = products[dayIndex].name;
  }

  // FALLBACK: Name match if positional didn't work
  if (!productId && productName) {
    const cleanName = productName.replace(/\s*\([^)]+\)\s*$/, '').trim();
    let match = products.find(p => p.name && p.name.toLowerCase() === cleanName.toLowerCase());
    if (!match) match = products.find(p => p.name && (p.name.toLowerCase().includes(cleanName.toLowerCase()) || cleanName.toLowerCase().includes(p.name.toLowerCase())));
    if (match) {
      productId = match.id;
      productName = match.name;
    }
  }

  let theme = dayThemeMap[dayNum] || null;
  if (!theme && t.storytelling_theme) {
    const normalized = t.storytelling_theme.toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_|_$/g, '');
    if (validThemes.includes(normalized)) {
      theme = normalized;
    } else {
      theme = validThemes.find(v => normalized.includes(v) || v.includes(normalized)) || null;
    }
  }

  return {
    user_id: prepData.user_id,
    campaign_id: prepData.campaign_id,
    week_number: prepData.week_number,
    day_number: dayNum,
    topic: t.topic || 'Topic ' + dayNum,
    description: t.description || '',
    content_angle: t.content_angle || 'General',
    product_id: productId,
    product_name: productName,
    status: 'pending',
    storytelling_theme: theme
  };
});

return {
  json: {
    topics: mapped,
    topics_body: JSON.stringify(mapped),
    user_id: prepData.user_id,
    campaign_id: prepData.campaign_id,
    week_number: prepData.week_number
  }
};

const saved = $input.item.json;
const parseData = $('Parse Topics').item.json;

// Return the saved topics (or original if save didn't return them)
let topics = [];
try {
  topics = Array.isArray(saved) ? saved : parseData.topics;
} catch(e) {
  topics = parseData.topics;
}

return {
  json: {
    success: true,
    topics: topics,
    week_number: parseData.week_number,
    campaign_id: parseData.campaign_id
  }
};

